// // This module implements a 3-bit down-counter that decrements its output on each positive clock edge. When reset is active, the counter resets to seven, and the carry_out signal is set to low. When the counter reaches its minimum value (0, or binary 000), it wraps around to seven and sets the carry_out signal high, indicating a count underflow.
module top_module(
    input clk,
    input rst,
    output reg [2:0] out,
    output reg carry_out
);always @(posedge clk) begin
        if (rst) begin
            out <= 3'b0;
            carry_out <= 1'b0;
        end
        else if (out == 3'b111) begin
            out <= 3'b0;
            carry_out <= 1'b1;
        end
        else begin
            out <= out + 1;
            carry_out <= 1'b0;
        end
    end

endmodule
